// export default Taskcard


import React, { useState } from 'react';

const Taskcard = ({ task }) => {
    const [subtasks, setSubtasks] = useState([]);

    function addtask() {
        const newtask = {
            id: Date.now(),
            content: ''
        };
        setSubtasks(prev => [...prev, newtask]);
    }

    function deletetask(id) {
        setSubtasks(prev => prev.filter((sub) => sub.id !== id));
    }

    return (
        <>
            <div className='task-card'>
                <div className='taskcard-header'>
                    <div className='task-title'>{task.title}</div>
                    <div className='task-icons'>
                        <div className='sub-icon'>
                            <button className='icon-button' onClick={addtask}>
                                <img className='icon-img' src='/assets/add.png' alt="Add" />
                            </button>
                        </div>
                    </div>
                </div>

                <div className='sub-tasks'>
                    {subtasks.map((sub) => (
                        <div key={sub.id} className='sub-task-items'>
                            <input type='checkbox' className='subtask-checkbox' />
                            <div
                                className='subtask-content'
                                contentEditable={true}
                                suppressContentEditableWarning={true}
                                placeholder="Enter subtask..."
                            ></div>
                            <button onClick={() => deletetask(sub.id)} className='delete-subtask'>❌</button>
                        </div>
                    ))}
                </div>
            </div>

            <Stylesheet />
        </>
    );
};

const Stylesheet = () => {
    return <style>{`
        .task-card {
            margin-bottom: 2rem;
            padding: 10px;
            background-color: var(--secondary-color);
            border-radius: 5px;
        }
        .taskcard-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 5px;
            background-color: var(--secondary-color);
            width: 250px;
        }
        .task-title {
            width: 100px;
            word-wrap: break-word;
        }
        .task-icons {
            display: flex;
            align-items: center;
        }
        .icon-button {
            background: none;
            border: none;
        }
        .icon-img {
            height: 20px;
            width: 30px;
        }
        .sub-tasks {
            display: flex;
            flex-direction: column;
            margin-top: 10px;
        }
        .sub-task-items {
            display: flex;
            align-items: flex-start;
            margin-bottom: 10px;
        }
        .subtask-checkbox {
            margin-right: 8px;
            margin-top: 6px;
        }
        .subtask-content {
            min-height: 40px;
            padding: 6px 8px;
            background-color: #fff;
            border: 1px solid #ccc;
            border-radius: 4px;
            flex: 1;
            resize: none;
            outline: none;
            white-space: pre-wrap;
        }
        .subtask-content:empty:before {
            content: attr(placeholder);
            color: #aaa;
        }
        .delete-subtask {
            background: none;
            border: none;
            margin-left: 6px;
            cursor: pointer;
        }
    `}</style>;
};

export default Taskcard;
